  ('dietitian-moex-10009', 'dietitian', 'dietitian-moex-095-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '仙人掌桿菌（Bacillus cereus）孢子具耐熱性，因此是食物中毒之危害因子之一。下列有關敘述，何者正確？', '["主要傳染媒介之一為生菜沙拉", "主要傳染媒介之一為煮熟米飯", "嘔吐型症狀之潛伏期為10~24 小時", "不會產生下痢"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:55+00:00", "source_pdf_sha1": "de2b260d4ee3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "095140", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "095", "exam_name": "095年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
